#!/usr/bin/env Rscript

# -----------------------------------------------------------------------------
# Figure 6D plotting script
#
# Purpose:
# Recreate cross-validated ROC-AUC trajectories across day cutoffs for linear
# models using post-quinolone microbiome features.
#
# Input:
# - document/tables/bsi_model_input.csv (generated by 04 script)
#
# Outputs:
# - document/tables/linearmodels_auc_cv_results.csv
# - document/plots/Fig6D.pdf
# -----------------------------------------------------------------------------

suppressPackageStartupMessages({
  library(tidyverse)
  library(pROC)
})

# -----------------------------------------------------------------------------
# 1) Ensure required directories / input table
# -----------------------------------------------------------------------------

if (!dir.exists("document/plots")) {
  dir.create("document/plots", recursive = TRUE)
}
if (!dir.exists("document/tables")) {
  dir.create("document/tables", recursive = TRUE)
}

if (!file.exists("document/tables/bsi_model_input.csv")) {
  source("code/scripts/04_generate_tblpatientday_clinical.R")
}

# -----------------------------------------------------------------------------
# 2) Theme, input loading, and feature-recalculation helper
# -----------------------------------------------------------------------------

custom_theme <- theme(
  panel.grid = element_blank(),
  panel.background = element_blank(),
  panel.border = element_rect(color = "black", fill = NA, linewidth = 0.75),
  axis.text = element_text(color = "black", size = 10)
)

message("Loading analysis table...")
# Sole analysis input table from script 04; includes sample-level taxa features
# and episode-level clinical cutoffs.
plot_input <- suppressMessages(read_csv("document/tables/bsi_model_input.csv")) %>%
  mutate(
    DayRelativeToNearestHCT = as.numeric(DayRelativeToNearestHCT),
    has_infection = as.logical(has_infection)
  )

# Recompute test-set patient-episode medians for each cutoff day.
# This mirrors the qmd strategy where test features are recalculated as if only
# data up to the cutoff were available.
recalc_patient_features_cutoff <- function(cutoff, test_patient_ids, input_tbl) {
  input_tbl %>%
    filter(PatientID %in% test_patient_ids) %>%
    mutate(
      max_day = pmin(
        cutoff,
        if_else(has_infection, first_infection_day, engraftment_day),
        na.rm = TRUE
      ),
      received_quin = !is.na(first_quin_day)
    ) %>%
    filter(
      received_quin,
      DayRelativeToNearestHCT >= first_quin_day,
      DayRelativeToNearestHCT < max_day
    ) %>%
    group_by(PatientID, TransplantEpisodeID, has_infection, received_quin) %>%
    summarise(
      median_proteobacteria_post = median(Proteobacteria_abund, na.rm = TRUE),
      median_ASV_277_abund_post = median(ASV_277_abund, na.rm = TRUE),
      median_bacteroidaceae_post = median(Bacteroidaceae_abund, na.rm = TRUE),
      median_tannerellaceae_post = median(Tannerellaceae_abund, na.rm = TRUE),
      n_samples_post = n(),
      .groups = "drop"
    )
}

# -----------------------------------------------------------------------------
# 3) Build patient-episode feature table for model training
# -----------------------------------------------------------------------------

message("Preparing patient-episode features...")

patient_features <- plot_input %>%
  mutate(
    cutoff_day = if_else(has_infection, first_infection_day, engraftment_day),
    received_quin = !is.na(first_quin_day)
  ) %>%
  filter(!is.na(cutoff_day), DayRelativeToNearestHCT < cutoff_day) %>%
  mutate(
    post_quin = received_quin & DayRelativeToNearestHCT >= first_quin_day
  ) %>%
  group_by(PatientID, TransplantEpisodeID, has_infection, received_quin) %>%
  summarise(
    median_bacteroidaceae_post = median(Bacteroidaceae_abund[post_quin], na.rm = TRUE),
    median_tannerellaceae_post = median(Tannerellaceae_abund[post_quin], na.rm = TRUE),
    median_proteobacteria_post = median(Proteobacteria_abund[post_quin], na.rm = TRUE),
    median_ASV_277_abund_post = median(ASV_277_abund[post_quin], na.rm = TRUE),
    n_samples_post = sum(post_quin, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  mutate(across(starts_with("median_"), ~ if_else(is.nan(.) | is.infinite(.), NA_real_, .)))

# Modeling cohort restricted to episodes with post-quinolone samples available.
features_post <- patient_features %>%
  filter(received_quin, n_samples_post > 0)

# -----------------------------------------------------------------------------
# 4) Define patient-level folds and model formulas
# -----------------------------------------------------------------------------

# Set seed
set.seed(75)

n_folds <- 5

# Assign fold at patient level so all transplant episodes from a patient remain
# in the same fold (prevents cross-fold leakage by patient ID).
# Fold map used to propagate one stratified fold assignment per patient.
patient_fold_map <- features_post %>%
  group_by(PatientID) %>%
  summarise(has_infection = any(has_infection), .groups = "drop") %>%
  group_by(has_infection) %>%
  mutate(fold = sample(rep(1:n_folds, length.out = n()))) %>%
  ungroup() %>%
  select(PatientID, fold)

features_post <- features_post %>%
  left_join(patient_fold_map, by = "PatientID")

cutoff_days <- -3:5

# Candidate model set evaluated across all fold/cutoff combinations.
model_formulas <- list(
  model1 = has_infection ~ log10(median_proteobacteria_post + 1e-05),
  model2 = has_infection ~ log10(median_bacteroidaceae_post + 1e-05),
  model3 = has_infection ~ log10(median_tannerellaceae_post + 1e-05),
  model4 = has_infection ~ log10(median_proteobacteria_post + 1e-05) * log10(median_bacteroidaceae_post + 1e-05),
  model5 = has_infection ~ log10(median_proteobacteria_post + 1e-05) * log10(median_tannerellaceae_post + 1e-05)
)

# -----------------------------------------------------------------------------
# 5) Cross-validation loop (recalculate test features per cutoff)
# -----------------------------------------------------------------------------

message("Running 5-fold CV across cutoff days...")

# Collector for fold-aggregated AUC summaries across models and cutoffs.
cv_auc_results <- list()

for (cutoff in cutoff_days) {
  fold_aucs <- list()

  for (fold_n in 1:n_folds) {
    test_patient_ids <- features_post %>% filter(fold == fold_n) %>% pull(PatientID)
    train_patient_ids <- features_post %>% filter(fold != fold_n) %>% pull(PatientID)

    test_set <- recalc_patient_features_cutoff(cutoff, test_patient_ids, plot_input)
    train_set <- features_post %>% filter(PatientID %in% train_patient_ids)

    for (model_name in names(model_formulas)) {
      form <- model_formulas[[model_name]]
      predictors <- all.vars(form)[-1]

      if (all(predictors %in% names(train_set)) && all(predictors %in% names(test_set))) {
        train_data <- train_set %>% drop_na(any_of(predictors), has_infection)
        test_data <- test_set %>% drop_na(any_of(predictors), has_infection)

        if (nrow(train_data) > 0 && nrow(test_data) > 0 && length(unique(test_data$has_infection)) > 1) {
          model <- glm(form, data = train_data, family = binomial)
          test_pred <- predict(model, newdata = test_data, type = "response")

          roc_obj <- tryCatch(
            pROC::roc(test_data$has_infection, test_pred, quiet = TRUE),
            error = function(e) NULL
          )
          auc <- if (!is.null(roc_obj)) as.numeric(roc_obj$auc) else NA_real_
          fold_aucs[[model_name]] <- c(fold_aucs[[model_name]], auc)
        } else {
          fold_aucs[[model_name]] <- c(fold_aucs[[model_name]], NA_real_)
        }
      } else {
        fold_aucs[[model_name]] <- c(fold_aucs[[model_name]], NA_real_)
      }
    }
  }

  for (model_name in names(model_formulas)) {
    aucs <- fold_aucs[[model_name]]
    cv_auc_results[[length(cv_auc_results) + 1]] <- tibble(
      model = model_name,
      cutoff = cutoff,
      mean_auc = mean(aucs, na.rm = TRUE),
      se_auc = sd(aucs, na.rm = TRUE) / sqrt(sum(!is.na(aucs))),
      sd_auc = sd(aucs, na.rm = TRUE),
      n_folds = sum(!is.na(aucs))
    )
  }
}

cv_auc_results_tbl <- bind_rows(cv_auc_results)
write_csv(cv_auc_results_tbl, "document/tables/linearmodels_auc_cv_results.csv")

# -----------------------------------------------------------------------------
# 6) Plot and save Figure 6D
# -----------------------------------------------------------------------------

message("Generating Fig6D...")

model_colors <- c(
  "model1" = "#e15454",
  "model2" = "#4ae1d9",
  "model3" = "#2c5362",
  "model4" = "#8B4789",
  "model5" = "#ec881e"
)

model_labels <- c(
  "model1" = "Pseudomonadota",
  "model2" = "Bacteroidaceae",
  "model3" = "Tannerellaceae",
  "model4" = "Pseudomonadota*Bacteroidaceae",
  "model5" = "Pseudomonadota*Tannerellaceae"
)

# Final Figure 6D plotting object (mean CV AUC +/- SE across cutoffs).
linearmodels_auc <- cv_auc_results_tbl %>%
  ggplot(aes(x = cutoff, y = mean_auc, color = model, fill = model, group = model)) +
  geom_ribbon(aes(ymin = mean_auc - se_auc, ymax = pmin(mean_auc + se_auc, 1)), alpha = 0.2, color = NA) +
  geom_line() +
  geom_point(size = 2) +
  scale_color_manual(values = model_colors, labels = model_labels) +
  scale_fill_manual(values = model_colors, labels = model_labels) +
  scale_y_continuous(limits = c(0, 1)) +
  labs(
    x = "Day relative to BMT (test cutoff)",
    y = "Mean test ROC-AUC (5-fold CV)",
    color = "Model features",
    fill = "Model features"
  ) +
  custom_theme +
  # Keep legend inside plot area to match original qmd presentation.
  theme(legend.position = c(0.5, 0.25))

ggsave("document/plots/Fig6D.pdf", linearmodels_auc, width = 7, height = 5)

message("Saved: document/tables/linearmodels_auc_cv_results.csv")
message("Saved: document/plots/Fig6D.pdf")
